const results = $input.first().json.results || [];
const topics = /ai\b|artificial intelligence|model|chip|smartphone|hardware|gpt|llm|regulation|policy/i;
const filtered = results.filter(r => topics.test((r.title || '') + ' ' + (r.description || '')));
return filtered.slice(0, 10).map(r => ({ json: {
  title: r.title,
  description: r.description || '',
  link: r.link,
  source: r.source_id,
  image_url: r.image_url || ''
}}));

