const blog = $('GitHub: get blog.html').item.json;
const index = $('GitHub: get index.html').item.json;
const mainRef = $('GitHub: get main ref').item.json;
const cardHtml = $('Render news-card HTML').item.json.cardHtml;
const HOME_TEASER_LIMIT = 4;

function decode(b64) { return Buffer.from(b64, 'base64').toString('utf-8'); }

// blog.html no longer carries a news section (news now lives only on the
// homepage as a scrolling feed) — left unchanged, but its sha is still
// needed so the PR diff for index.html applies cleanly against the same branch.
function insertIntoIndex(html) {
  const sectionMarker = '<section class="news-section" id="latest-ai-news">';
  const sectionStart = html.indexOf(sectionMarker);
  if (sectionStart === -1) throw new Error('latest-ai-news section not found in index.html');
  const gridMarker = '<div class="news-grid news-feed">';
  const gridIdx = html.indexOf(gridMarker, sectionStart);
  const insertAt = gridIdx + gridMarker.length;
  let updated = html.slice(0, insertAt) + '\n' + cardHtml + html.slice(insertAt);

  const gridIdx2 = updated.indexOf(gridMarker, sectionStart);
  const gridClose = updated.indexOf('</div>', gridIdx2);
  const gridInner = updated.slice(gridIdx2 + gridMarker.length, gridClose);
  const articleRe = /<article class="news-card">[\s\S]*?<\/article>\s*/g;
  const articles = gridInner.match(articleRe) || [];
  if (articles.length > HOME_TEASER_LIMIT) {
    const trimmed = '\n' + articles.slice(0, HOME_TEASER_LIMIT).join('');
    updated = updated.slice(0, gridIdx2 + gridMarker.length) + trimmed + updated.slice(gridClose);
  }
  return updated;
}

const blogHtml = decode(blog.content);
const indexHtml = decode(index.content);
const newIndexHtml = insertIntoIndex(indexHtml);

return [{ json: {
  baseSha: mainRef.object.sha,
  blogSha: blog.sha,
  indexSha: index.sha,
  blogContentB64: Buffer.from(blogHtml, 'utf-8').toString('base64'),
  indexContentB64: Buffer.from(newIndexHtml, 'utf-8').toString('base64'),
  branchName: 'ai-news/' + new Date().toISOString().slice(0,10) + '-' + Math.random().toString(36).slice(2,7)
}}];

